import React, { useState, useEffect } from 'react';
import {
  Badge,
  Box,
  Avatar,
  Divider,
  Menu,
  MenuItem,
  Typography,
  IconButton,
} from '@mui/material';
import { Link, useNavigate, useLocation } from 'react-router-dom';
import {
  ShoppingCartOutlined,
  PersonOutline,
  DashboardOutlined,
  Inventory2Outlined,
  LogoutOutlined,
  StorefrontOutlined,
} from '@mui/icons-material';
import { useAuth } from '../../context/AuthContext';
import { cartAPI } from '../../services/api';

const NAV_LINKS = [
  { label: 'Home', to: '/' },
  { label: 'Collections', to: '/products' },
  { label: 'Heritage', to: '/about' },
  { label: 'Journal', to: '/journal' },
  { label: 'Contact', to: '/contact' },
  { label: '3D Experience', to: '/experience-3d' },
];

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();
  const [cartCount, setCartCount] = useState(0);
  const [anchorEl, setAnchorEl] = useState(null);
  const [scrolled, setScrolled] = useState(false);

  useEffect(() => {
    const onScroll = () => setScrolled(window.scrollY > 20);
    window.addEventListener('scroll', onScroll, { passive: true });
    return () => window.removeEventListener('scroll', onScroll);
  }, []);

  useEffect(() => {
    const fetchCartCount = async () => {
      if (user) {
        try {
          const response = await cartAPI.get();
          const count = response.data.cart?.items?.reduce((t, i) => t + i.quantity, 0) || 0;
          setCartCount(count);
        } catch {
          /* ignore */
        }
      } else {
        setCartCount(0);
      }
    };
    fetchCartCount();
    const interval = setInterval(fetchCartCount, 30000);
    return () => clearInterval(interval);
  }, [user]);

  const handleLogout = () => {
    logout();
    navigate('/');
    setAnchorEl(null);
  };

  const isActive = (path) => location.pathname === path || location.pathname.startsWith(path + '/');

  return (
    <nav
      style={{
        position: 'sticky',
        top: 0,
        zIndex: 1200,
        background: scrolled ? 'var(--lx-black)' : 'var(--lx-black)',
        borderBottom: scrolled ? '1px solid var(--lx-border-light)' : '1px solid transparent',
        transition: 'all 0.3s ease',
        padding: '0 40px',
      }}
    >
      <div
        style={{
          maxWidth: 1440,
          margin: '0 auto',
          display: 'grid',
          gridTemplateColumns: '1fr auto 1fr',
          alignItems: 'center',
          height: 80,
        }}
      >
        {/* Left: Navigation Links */}
        <Box sx={{ display: { xs: 'none', md: 'flex' }, alignItems: 'center', gap: 4 }}>
          {NAV_LINKS.map(({ label, to }) => (
            <Link
              key={to}
              to={to}
              style={{
                textDecoration: 'none',
                fontFamily: '"Outfit", sans-serif',
                fontWeight: 500,
                fontSize: '0.85rem',
                letterSpacing: '0.08em',
                textTransform: 'uppercase',
                color: isActive(to) ? 'var(--lx-beige)' : 'var(--lx-text-secondary)',
                transition: 'color 0.2s ease',
                position: 'relative',
              }}
              onMouseEnter={(e) => { e.currentTarget.style.color = 'var(--lx-beige)'; }}
              onMouseLeave={(e) => { if (!isActive(to)) e.currentTarget.style.color = 'var(--lx-text-secondary)'; }}
            >
              {label}
            </Link>
          ))}
        </Box>

        {/* Center: Logo */}
        <Link
          to="/"
          style={{
            textDecoration: 'none',
            display: 'flex',
            alignItems: 'center',
            justifyContent: 'center',
          }}
        >
          <span
            style={{
              fontFamily: '"Outfit", sans-serif',
              fontWeight: 600,
              fontSize: '1.6rem',
              letterSpacing: '0.05em',
              color: 'var(--lx-text-primary)'
            }}
          >
            FlyingWood
          </span>
        </Link>

        {/* Right: Actions */}
        <Box sx={{ display: 'flex', alignItems: 'center', justifyContent: 'flex-end', gap: 2 }}>
          {/* Cart */}
          <IconButton
            component={Link}
            to="/cart"
            disableRipple
            sx={{
              color: 'var(--lx-text-primary)',
              transition: 'opacity 0.2s ease',
              '&:hover': { opacity: 0.7, background: 'transparent' },
            }}
          >
            <Badge
              badgeContent={cartCount}
              sx={{
                '& .MuiBadge-badge': {
                  background: 'var(--lx-beige)',
                  color: 'var(--lx-black)',
                  fontSize: '0.65rem',
                  fontWeight: 600,
                  fontFamily: '"Outfit", sans-serif',
                  minWidth: 16,
                  height: 16,
                  padding: '0 4px',
                },
              }}
            >
              <ShoppingCartOutlined sx={{ fontSize: 22 }} />
            </Badge>
          </IconButton>

          {user ? (
            <>
              <IconButton
                onClick={(e) => setAnchorEl(e.currentTarget)}
                disableRipple
                sx={{
                  color: 'var(--lx-text-primary)',
                  transition: 'opacity 0.2s ease',
                  '&:hover': { opacity: 0.7, background: 'transparent' },
                }}
              >
                <PersonOutline sx={{ fontSize: 24 }} />
              </IconButton>

              <Menu
                anchorEl={anchorEl}
                open={Boolean(anchorEl)}
                onClose={() => setAnchorEl(null)}
                PaperProps={{
                  sx: {
                    mt: 2,
                    minWidth: 240,
                    background: 'var(--lx-charcoal)',
                    border: '1px solid var(--lx-border-light)',
                    borderRadius: '4px',
                    boxShadow: 'var(--lx-shadow-md)',
                    '& .MuiMenuItem-root': {
                      fontFamily: '"Outfit", sans-serif',
                      fontSize: '0.85rem',
                      letterSpacing: '0.04em',
                      textTransform: 'uppercase',
                      py: 1.5,
                      px: 3,
                      color: 'var(--lx-text-secondary)',
                      '&:hover': {
                        background: 'var(--lx-surface-elevated)',
                        color: 'var(--lx-beige)',
                      },
                    },
                  },
                }}
                transformOrigin={{ horizontal: 'right', vertical: 'top' }}
                anchorOrigin={{ horizontal: 'right', vertical: 'bottom' }}
              >
                <Box sx={{ px: 3, py: 2.5 }}>
                  <Typography
                    sx={{
                      fontFamily: '"Outfit", sans-serif',
                      fontWeight: 500,
                      fontSize: '1rem',
                      color: 'var(--lx-text-primary)',
                      mb: 0.5
                    }}
                  >
                    {user.username}
                  </Typography>
                  <Typography
                    sx={{
                      fontFamily: '"Inter", sans-serif',
                      fontSize: '0.8rem',
                      color: 'var(--lx-text-tertiary)',
                      mb: 1.5
                    }}
                  >
                    {user.email}
                  </Typography>
                  <span className="badge-lx">{user.role}</span>
                </Box>

                <Divider sx={{ borderColor: 'var(--lx-border-light)', mx: 2 }} />

                <MenuItem onClick={() => { navigate('/profile'); setAnchorEl(null); }}>
                  <PersonOutline sx={{ mr: 2, fontSize: 18 }} /> Account Details
                </MenuItem>

                {user.role === 'admin' && [
                  <MenuItem key="admin" onClick={() => { navigate('/admin'); setAnchorEl(null); }}>
                    <DashboardOutlined sx={{ mr: 2, fontSize: 18 }} /> Administration
                  </MenuItem>,
                  <MenuItem key="vendors" onClick={() => { navigate('/vendor'); setAnchorEl(null); }}>
                    <StorefrontOutlined sx={{ mr: 2, fontSize: 18 }} /> Vendor Directory
                  </MenuItem>,
                ]}

                {user.role === 'vendor' && [
                  <MenuItem key="vendor" onClick={() => { navigate('/vendor'); setAnchorEl(null); }}>
                    <Inventory2Outlined sx={{ mr: 2, fontSize: 18 }} /> Catalog Management
                  </MenuItem>,
                ]}

                <Divider sx={{ borderColor: 'var(--lx-border-light)', mx: 2 }} />

                <MenuItem onClick={handleLogout}>
                  <LogoutOutlined sx={{ mr: 2, fontSize: 18 }} /> Sign Out
                </MenuItem>
              </Menu>
            </>
          ) : (
            <Link
              to="/login"
              style={{
                textDecoration: 'none',
                fontFamily: '"Outfit", sans-serif',
                fontWeight: 500,
                fontSize: '0.85rem',
                letterSpacing: '0.08em',
                textTransform: 'uppercase',
                color: 'var(--lx-text-primary)',
                transition: 'color 0.2s ease',
                marginLeft: 16
              }}
              onMouseEnter={(e) => { e.currentTarget.style.color = 'var(--lx-beige)'; }}
              onMouseLeave={(e) => { e.currentTarget.style.color = 'var(--lx-text-primary)'; }}
            >
              Sign In
            </Link>
          )}
        </Box>
      </div>
    </nav>
  );
};

export default Navbar;

import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  Typography,
  Button,
  CircularProgress,
  Alert,
  Divider
} from '@mui/material';
import {
  CardElement,
  useStripe,
  useElements
} from '@stripe/react-stripe-js';
import { usePayment } from '../../context/PaymentContext';
import { useSnackbar } from 'notistack';

const cardElementOptions = {
  style: {
    base: {
      fontSize: '16px',
      color: '#424770',
      '::placeholder': {
        color: '#aab7c4',
      },
      padding: '10px 12px',
    },
    invalid: {
      color: '#9e2146',
    },
  },
  hidePostalCode: true
};

const StripePayment = ({ order, onSuccess, onBack }) => {
  const stripe = useStripe();
  const elements = useElements();
  const { createPaymentIntent, confirmPayment, loading, error } = usePayment();
  const { enqueueSnackbar } = useSnackbar();

  const [clientSecret, setClientSecret] = useState('');
  const [paymentProcessing, setPaymentProcessing] = useState(false);
  const [cardComplete, setCardComplete] = useState(false);

  useEffect(() => {
    if (order && order._id) {
      initializePayment();
    }
  }, [order]);

  const initializePayment = async () => {
    try {
      const { clientSecret, totalAmount } = await createPaymentIntent(order._id);
      setClientSecret(clientSecret);
    } catch (err) {
      enqueueSnackbar('Failed to initialize payment', { variant: 'error' });
    }
  };

  const handleSubmit = async (event) => {
    event.preventDefault();

    if (!stripe || !elements || !clientSecret) {
      return;
    }

    setPaymentProcessing(true);

    try {
      const { error: stripeError, paymentIntent } = await stripe.confirmCardPayment(
        clientSecret,
        {
          payment_method: {
            card: elements.getElement(CardElement),
            billing_details: {
              name: order.shippingAddress.fullName,
              email: order.user.email,
              address: {
                line1: order.shippingAddress.address,
                city: order.shippingAddress.city,
                state: order.shippingAddress.state,
                postal_code: order.shippingAddress.postalCode,
                country: 'US',
              },
            },
          },
        }
      );

      if (stripeError) {
        enqueueSnackbar(stripeError.message, { variant: 'error' });
      } else if (paymentIntent.status === 'succeeded') {
        // Confirm payment with our backend
        await confirmPayment(order._id, paymentIntent.id);

        enqueueSnackbar('Payment successful! Order confirmed.', { variant: 'success' });
        onSuccess();
      }
    } catch (err) {
      enqueueSnackbar('Payment failed. Please try again.', { variant: 'error' });
    } finally {
      setPaymentProcessing(false);
    }
  };

  const handleCardChange = (event) => {
    setCardComplete(event.complete);
  };

  return (
    <Box component="form" onSubmit={handleSubmit}>
      <Typography variant="h5" gutterBottom fontWeight="bold">
        Payment Information
      </Typography>

      <Card sx={{ p: 3, mb: 3 }}>
        <Typography variant="h6" gutterBottom>
          Credit/Debit Card
        </Typography>

        {error && (
          <Alert severity="error" sx={{ mb: 2 }} onClose={clearError}>
            {error}
          </Alert>
        )}

        <Box sx={{ mb: 3 }}>
          <Typography variant="body2" color="text.secondary" gutterBottom>
            Card Details
          </Typography>
          <Box 
            sx={{ 
              border: 1, 
              borderColor: 'grey.300', 
              borderRadius: 1, 
              p: 2,
              bgcolor: 'background.paper'
            }}
          >
            <CardElement 
              options={cardElementOptions}
              onChange={handleCardChange}
            />
          </Box>
        </Box>

        <Divider sx={{ my: 2 }} />

        {/* Order Summary */}
        <Box sx={{ mb: 3 }}>
          <Typography variant="h6" gutterBottom>
            Order Summary
          </Typography>
          <Box display="flex" justifyContent="space-between" mb={1}>
            <Typography variant="body2">Subtotal:</Typography>
            <Typography variant="body2">${order.subtotal?.toFixed(2)}</Typography>
          </Box>
          <Box display="flex" justifyContent="space-between" mb={1}>
            <Typography variant="body2">Shipping:</Typography>
            <Typography variant="body2">${order.shippingPrice?.toFixed(2)}</Typography>
          </Box>
          <Box display="flex" justifyContent="space-between" mb={1}>
            <Typography variant="body2">Tax:</Typography>
            <Typography variant="body2">${order.taxPrice?.toFixed(2)}</Typography>
          </Box>
          <Divider sx={{ my: 1 }} />
          <Box display="flex" justifyContent="space-between">
            <Typography variant="h6">Total:</Typography>
            <Typography variant="h6" color="primary">
              ${order.totalAmount?.toFixed(2)}
            </Typography>
          </Box>
        </Box>

        <Box display="flex" gap={2}>
          <Button
            variant="outlined"
            onClick={onBack}
            disabled={paymentProcessing}
            fullWidth
          >
            Back
          </Button>
          <Button
            type="submit"
            variant="contained"
            disabled={!stripe || !cardComplete || paymentProcessing || loading}
            fullWidth
            size="large"
          >
            {paymentProcessing ? (
              <CircularProgress size={24} />
            ) : (
              `Pay $${order.totalAmount?.toFixed(2)}`
            )}
          </Button>
        </Box>

        <Typography variant="caption" color="text.secondary" sx={{ mt: 2, display: 'block' }}>
          Your payment is secure and encrypted. We never store your card details.
        </Typography>
      </Card>
    </Box>
  );
};

export default StripePayment;

import React, { useState, useEffect } from 'react';
import {
  Box,
  Card,
  Typography,
  Rating,
  Avatar,
  Chip,
  Button
} from '@mui/material';
import { ThumbUp } from '@mui/icons-material';

const ReviewList = ({ productId }) => {
  const [reviews, setReviews] = useState([]);

  useEffect(() => {
    fetchReviews();
  }, [productId]);

  const fetchReviews = async () => {
    try {
      const response = await api.get(`/reviews/product/${productId}`);
      setReviews(response.data);
    } catch (error) {
      console.error('Failed to fetch reviews');
    }
  };

  const handleHelpful = async (reviewId) => {
    try {
      await api.patch(`/reviews/${reviewId}/helpful`);
      // Update local state
      setReviews(reviews.map(review => 
        review._id === reviewId 
          ? { ...review, helpful: review.helpful + 1 }
          : review
      ));
    } catch (error) {
      console.error('Failed to mark as helpful');
    }
  };

  return (
    <Box>
      <Typography variant="h6" gutterBottom>
        Customer Reviews ({reviews.length})
      </Typography>

      {reviews.map((review) => (
        <Card key={review._id} sx={{ p: 3, mb: 2 }}>
          <Box display="flex" alignItems="center" mb={1}>
            <Avatar src={review.user.avatar} sx={{ mr: 2 }}>
              {review.user.name.charAt(0)}
            </Avatar>
            <Box>
              <Typography variant="subtitle1">{review.user.name}</Typography>
              <Box display="flex" alignItems="center">
                <Rating value={review.rating} size="small" readOnly />
                <Typography variant="caption" sx={{ ml: 1 }}>
                  {new Date(review.createdAt).toLocaleDateString()}
                </Typography>
              </Box>
            </Box>
          </Box>

          <Typography variant="h6" gutterBottom>{review.title}</Typography>
          <Typography variant="body2" paragraph>{review.comment}</Typography>

          <Box display="flex" justifyContent="space-between" alignItems="center">
            {review.verifiedPurchase && (
              <Chip label="Verified Purchase" color="success" size="small" />
            )}

            <Button
              startIcon={<ThumbUp />}
              size="small"
              onClick={() => handleHelpful(review._id)}
            >
              Helpful ({review.helpful})
            </Button>
          </Box>
        </Card>
      ))}
    </Box>
  );
};

export default ReviewList;

import React, { useState, useEffect, useRef } from 'react';
import {
  Box,
  Card,
  CardContent,
  Typography,
  Button,
  IconButton,
  Chip,
  CircularProgress,
  Tooltip,
} from '@mui/material';
import {
  ViewInAr,
  ShoppingCart,
  Favorite,
  FavoriteBorder,
  ErrorOutline,
  Visibility,
} from '@mui/icons-material';
import { Link, useNavigate } from 'react-router-dom';
import { formatPrice } from '../../utils/currency';

const API_URL = process.env.REACT_APP_API_URL || 'http://localhost:5001';

const ProductCard = ({ 
  product, 
  viewMode = 'grid', 
  onBuyNow, 
  onWishlistToggle, 
  isInWishlist = false,
  show3D = false
}) => {
  const navigate = useNavigate();
  const [hasError, setHasError] = useState(false);
  const [isLoaded, setIsLoaded] = useState(false);
  const modelViewerRef = useRef(null);

  const modelUrl = product.model3D 
    ? (product.model3D.startsWith('http') ? product.model3D : `${API_URL}${product.model3D}`) 
    : '';

  const posterUrl = product.images?.[0]?.url 
    ? (product.images[0].url.startsWith('http') ? product.images[0].url : `${API_URL}${product.images[0].url}`) 
    : 'https://via.placeholder.com/400x400?text=FlyingWood+Furniture';

  useEffect(() => {
    const viewer = modelViewerRef.current;
    if (!viewer) return;

    const handleError = (error) => {
      console.error('Model Viewer Error:', error);
      setHasError(true);
    };

    const handleLoad = () => {
      setIsLoaded(true);
      setHasError(false);
    };

    viewer.addEventListener('error', handleError);
    viewer.addEventListener('load', handleLoad);

    return () => {
      viewer.removeEventListener('error', handleError);
      viewer.removeEventListener('load', handleLoad);
    };
  }, [modelUrl]);

  const handleCardClick = () => {
    navigate(`/products/${product._id || product.id}`);
  };

  const isList = viewMode === 'list';

  return (
    <Card 
      sx={{ 
        height: '100%', 
        display: 'flex', 
        flexDirection: isList ? 'row' : 'column',
        bgcolor: 'var(--lx-charcoal)',
        border: '1px solid var(--lx-border-light)',
        transition: 'var(--lx-transition)',
        '&:hover': {
          borderColor: 'var(--lx-border)',
          transform: 'translateY(-4px)',
          boxShadow: 'var(--lx-shadow-md)'
        }
      }}
    >
      {/* Media Section */}
      <Box 
        sx={{ 
          position: 'relative', 
          width: isList ? '35%' : '100%', 
          height: isList ? 'auto' : 320,
          minHeight: isList ? 240 : 'auto',
          bgcolor: '#000',
          cursor: 'pointer',
          overflow: 'hidden'
        }}
        onClick={handleCardClick}
      >
        {product.has3D && !hasError && show3D ? (
          <Box 
            onClick={(e) => { e.preventDefault(); e.stopPropagation(); }} 
            sx={{ width: '100%', height: '100%' }}
          >
            <model-viewer 
              ref={modelViewerRef}
              src={modelUrl}
            poster={posterUrl}
            alt={product.name}
            auto-rotate
            camera-controls
            shadow-intensity="1"
            environment-image="neutral"
            exposure="1"
            loading="lazy"
            reveal="auto"
            style={{ width: '100%', height: '100%', outline: 'none' }}
          >
            <Box 
              slot="poster" 
              sx={{ 
                width: '100%', 
                height: '100%', 
                backgroundImage: `url(${posterUrl})`,
                backgroundSize: 'cover',
                backgroundPosition: 'center',
                display: 'flex',
                alignItems: 'center',
                justifyContent: 'center'
              }}
            >
              {!isLoaded && <CircularProgress size={24} sx={{ color: 'var(--lx-beige)' }} />}
            </Box>
            <Box slot="progress-bar" sx={{ display: 'none' }} />
            </model-viewer>
          </Box>
        ) : (
          <Box 
            component="img"
            src={posterUrl}
            alt={product.name}
            sx={{ 
              width: '100%', 
              height: '100%', 
              objectFit: 'cover',
              transition: 'transform 0.6s cubic-bezier(0.16, 1, 0.3, 1)',
              '.lx-card:hover &': { transform: 'scale(1.05)' }
            }}
          />
        )}

        {/* Overlay Badges */}
        {product.has3D && (
          <Chip 
            label="Live 3D" 
            size="small"
            icon={<ViewInAr sx={{ fontSize: '14px !important' }} />}
            sx={{ 
              position: 'absolute', 
              top: 12, 
              left: 12, 
              bgcolor: 'rgba(12, 12, 12, 0.7)',
              backdropFilter: 'blur(8px)',
              color: 'var(--lx-text-primary)',
              fontSize: '10px',
              fontWeight: 600,
              border: '1px solid var(--lx-border)',
              zIndex: 2,
              pointerEvents: 'none'
            }} 
          />
        )}

        <Tooltip title={isInWishlist ? "Remove from wishlist" : "Add to wishlist"}>
          <IconButton
            sx={{ 
              position: 'absolute', 
              top: 12, 
              right: 12, 
              bgcolor: 'rgba(12, 12, 12, 0.5)', 
              backdropFilter: 'blur(8px)',
              color: isInWishlist ? 'var(--lx-gold-soft)' : 'var(--lx-text-secondary)',
              '&:hover': { bgcolor: 'rgba(12, 12, 12, 0.8)' },
              zIndex: 2
            }}
            onClick={(e) => {
              e.stopPropagation();
              onWishlistToggle && onWishlistToggle(product._id || product.id);
            }}
          >
            {isInWishlist ? <Favorite /> : <FavoriteBorder />}
          </IconButton>
        </Tooltip>
      </Box>

      {/* Content Section */}
      <CardContent sx={{ 
        flexGrow: 1, 
        p: 3, 
        display: 'flex', 
        flexDirection: 'column',
        width: isList ? '65%' : '100%' 
      }}>
        <Box sx={{ flexGrow: 1 }}>
          <Typography variant="overline" sx={{ color: 'var(--lx-gold-soft)', letterSpacing: '0.1em', fontWeight: 600 }}>
            {product.category || 'Collection'}
          </Typography>
          <Typography 
            variant={isList ? "h4" : "h6"} 
            component="h2" 
            sx={{ 
              color: 'var(--lx-text-primary)', 
              mb: 1, 
              fontWeight: 500,
              cursor: 'pointer',
              '&:hover': { color: 'var(--lx-beige)' }
            }}
            onClick={handleCardClick}
          >
            {product.name}
          </Typography>
          <Typography 
            variant="body2" 
            sx={{ 
              color: 'var(--lx-text-secondary)', 
              mb: 2, 
              lineHeight: 1.6,
              display: '-webkit-box',
              WebkitLineClamp: isList ? 3 : 2,
              WebkitBoxOrient: 'vertical',
              overflow: 'hidden'
            }}
          >
            {product.shortDescription || product.description}
          </Typography>
        </Box>

        <Box sx={{ 
          display: 'flex', 
          justifyContent: 'space-between', 
          alignItems: 'center', 
          pt: 2, 
          borderTop: '1px solid var(--lx-border-light)',
          mt: 'auto'
        }}>
          <Typography variant="h6" sx={{ color: 'var(--lx-text-primary)', fontWeight: 600 }}>
            {formatPrice(product.price)}
          </Typography>
          <Box sx={{ display: 'flex', gap: 1 }}>
            <Tooltip title="Quick View">
              <IconButton 
                component={Link} 
                to={`/products/${product._id || product.id}`}
